Rule.Source:
import sailpoint.api.Workflower;
  import sailpoint.object.Certification;
  import sailpoint.object.CertificationAction;
  import sailpoint.object.CertificationEntity;
  import sailpoint.object.CertificationItem;
  import sailpoint.object.Workflow;
  import sailpoint.tools.Util;

  boolean hasRemediations = false;

  if (certification != null) {

    List entities = certification.getEntities();

    for (CertificationEntity entity : entities) {

      List certItems = entity.getItems();

      for (CertificationItem item : certItems) {

        if (Util.nullSafeCaseInsensitiveEq(item.getAction().getStatus().toString(), "Remediated")) {

          hasRemediations = true;

          item.getAction().setRemediationDetails(null); //Null Out ProvisioningPlan to Mitigate Connector Exceptions 

        }

      }

    }

  }

  if (hasRemediations) {
  
  //Launch a Workflow to Handle Remediations

  Workflower workflower = new Workflower(context);
  String workflowName = "Ascension-Workflow-NestedGWSGroup-Remediations";
  String caseName = "Ascension-NestedGWSGroup-Remediations-" + certification.getId();
  Map vars = new HashMap();
  vars.put("certificationObj", certification);

  Workflow workflow = context.getObjectByName(Workflow.class, workflowName);

  if (workflower != null && workflow != null) {
    log.trace("Launching async workflow: " + workflowName);
    workflower.launchSafely(workflow, caseName, vars);
  }

  }
